INSERT INTO public.sop_master (sop_name, process_step, purpose, scope, procedure_text, frequency, responsible, related_prp) VALUES
('Receiving Inspection Procedure', 'Receiving', 'Ensure all incoming materials meet safety standards', 'All incoming food and materials', '1. Check supplier approval 2. Inspect packaging 3. Check temperature if required 4. Accept or reject materials', 'Each Delivery', 'Staff', 'Supplier Control Program'),
